{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires relating the observed exciton peak energy to the Rydberg energy using the hydrogenic model for excitons, then calculating the specific energy level for n=3.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Identify and define the following: the band gap energy (Eg), the observed 1s exciton peak energy (E_ex_1s), the relationship between the band gap and the 1s exciton binding energy (Eb_1s), the formula for the energy levels of a hydrogenic exciton (En), and the sign convention for binding energy versus total energy relative to the band edge."
    },
    {
      "label": "helper_2",
      "instructions": "Using the values from helper 1, calculate the 1s Rydberg energy (Ry*) using the relation Eb_1s = Ry* / (1^2). Then, use the Rydberg formula En = -Ry* / (n^2) to calculate the energy for the n = 3 state. Ensure the final value reflects the correct sign as requested by the problem (the energy level relative to the band edge)."
    }
  ],
  "synthesis_brief": "Combine the calculated Rydberg energy (Ry*) and the specific energy level for n=3 (E3) into the final answer, ensuring the sign is correct based on whether the question asks for the binding energy or the energy level relative to the conduction band edge."
}

